// Verify the JWT from the Authorization header
const authHeader = $('Webhook').item.json.headers?.authorization ?? '';
const token = authHeader.replace(/^Bearer\s+/i, '');
if (!token) throw new Error('Missing authorization token');

// Exchange token for user via Supabase
const res = await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/auth/v1/user`, {
  headers: {
    Authorization: `Bearer ${token}`,
    apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
  },
});
if (!res.ok) throw new Error('Invalid or expired token');
const user = await res.json();

// Verify ownership: agency_owner → client → conversation
const body = $('Webhook').item.json.body;
const { conversationId, message } = body;

const ownerRes = await fetch(
  `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/agency_owners?user_id=eq.${user.id}&select=id`,
  { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
);
const owners = await ownerRes.json();
if (!owners.length) throw new Error('No agency owner found');
const ownerId = owners[0].id;

const convRes = await fetch(
  `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/conversations?id=eq.${conversationId}&select=id,lead_phone,client_id,clients(respondfall_number,agency_owner_id)`,
  { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
);
const convs = await convRes.json();
if (!convs.length) throw new Error('Conversation not found');
const conv = convs[0];
if (conv.clients.agency_owner_id !== ownerId) throw new Error('Unauthorized');

return [{ json: { conv, message, token } }];
